                >
                  {loading ? <i className="fa-solid fa-sync fa-spin"></i> : <i className="fa-solid fa-wand-sparkles"></i>}
                  AI Medical Briefing
                </button>
              </div>

              {aiSummary && (
                <div className="mb-10 p-8 bg-[#1B365D] rounded-3xl text-white relative border-b-4 border-b-[#C5A059]">
                   <i className="fa-solid fa-quote-left absolute top-4 left-4 text-white/5 text-4xl"></i>
                   <p className="text-sm leading-relaxed font-medium italic opacity-90">{aiSummary}</p>
                </div>
