              <div className="space-y-4">
                {selectedPatient.medicalHistory.map((item, idx) => (
                  <div key={idx} className="flex gap-6 items-start p-6 bg-slate-50/50 hover:bg-slate-50 rounded-2xl transition-all border border-transparent hover:border-slate-200 group">
                    <div className="w-12 h-12 bg-white rounded-xl shadow-sm flex items-center justify-center text-[#4189DD] font-black group-hover:scale-110 transition-transform">
