            </div>
          </div>
        </div>
      ) : (
        <div className="h-80 bg-white border-4 border-dashed border-slate-100 rounded-[3rem] flex flex-col items-center justify-center text-slate-300">
           <i className="fa-solid fa-database text-6xl mb-6 opacity-20"></i>
           <p className="font-black uppercase tracking-[0.2em] text-sm">Waiting for Identity Verification</p>
        </div>
      )}
    </div>
  );
};

